"""Stop / restart the AgentPulse service from the tray app.

Linux  : shells out to ``systemctl --user stop|restart agentpulse``.
Windows: reads the service PID file written at startup by app.py and
         terminates exactly that PID (with a safety check that the
         target process actually looks like agentpulse). If no pidfile
         exists, logs a warning and does nothing rather than guessing.

The previous implementation iterated every process and matched any
command line containing the substring ``agentpulse`` — which caught
VS Code, git bash, Claude Code, and the tray itself when the workspace
path contained that string.
"""

import logging
import subprocess
import sys
import time
from pathlib import Path

from agentpulse import pidfile, winutil
from agentpulse.app import SERVICE_PIDFILE_NAME

logger = logging.getLogger(__name__)

SYSTEMD_UNIT = "agentpulse"
_TERMINATE_WAIT_SECONDS = 5.0

# Set by the tray at startup via configure(). Used to launch the service
# with the same config file the tray itself is using.
_service_config_path: Path | None = None


def configure(*, config_path: Path) -> None:
    """Record the config path to use when (re)launching the service."""
    global _service_config_path
    _service_config_path = config_path


def _terminate_service_pid() -> bool:
    """Terminate the PID recorded in the service pidfile.

    Returns True if a process was asked to terminate, False otherwise.
    """
    pid = pidfile.read_pid(SERVICE_PIDFILE_NAME)
    if pid is None:
        logger.warning(
            "no service pidfile at %s; cannot identify service process",
            pidfile.pidfile_path(SERVICE_PIDFILE_NAME),
        )
        return False

    if not pidfile.is_process_ours(pid, must_contain="agentpulse"):
        logger.warning(
            "pidfile pid=%d is stale or does not look like agentpulse; skipping",
            pid,
        )
        pidfile.remove_pid(SERVICE_PIDFILE_NAME)
        return False

    import psutil

    try:
        proc = psutil.Process(pid)
        proc.terminate()
        try:
            proc.wait(timeout=_TERMINATE_WAIT_SECONDS)
        except psutil.TimeoutExpired:
            logger.warning(
                "pid=%d did not exit within %.1fs; killing",
                pid,
                _TERMINATE_WAIT_SECONDS,
            )
            proc.kill()
        return True
    except psutil.NoSuchProcess:
        return False
    finally:
        pidfile.remove_pid(SERVICE_PIDFILE_NAME)


def _launch_windows() -> None:
    """Launch the service as a detached, console-less child process.

    Uses pythonw.exe (sibling of sys.executable) so no console window
    attaches. Reuses the same interpreter environment as the tray so
    the launch works across pipx, dev venvs, and other layouts.
    """
    if _service_config_path is None:
        logger.error("supervisor.configure() was not called; cannot launch service")
        return

    # Detach from the tray so the service survives tray exit and does not
    # receive Ctrl+C events routed to the tray's console.
    creationflags = 0
    for flag_name in ("DETACHED_PROCESS", "CREATE_NEW_PROCESS_GROUP"):
        creationflags |= getattr(subprocess, flag_name, 0)

    cmd = [
        winutil.pythonw_path(),
        "-m",
        "agentpulse",
        "--config",
        str(_service_config_path),
    ]
    logger.info("launching service: %s", " ".join(cmd))
    try:
        subprocess.Popen(
            cmd,
            creationflags=creationflags,
            close_fds=True,
            stdin=subprocess.DEVNULL,
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
        )
    except OSError:
        logger.exception("failed to launch service")


def stop_service() -> None:
    if sys.platform == "linux":
        subprocess.run(["systemctl", "--user", "stop", SYSTEMD_UNIT], check=False)
        return
    if sys.platform == "win32":
        _terminate_service_pid()
        return
    logger.warning("unsupported platform: %s", sys.platform)


def restart_service() -> None:
    if sys.platform == "linux":
        subprocess.run(["systemctl", "--user", "restart", SYSTEMD_UNIT], check=False)
        return
    if sys.platform == "win32":
        terminated = _terminate_service_pid()
        if terminated:
            # small grace period so the port is released before relaunch
            time.sleep(0.5)
        _launch_windows()
        return
    logger.warning("unsupported platform: %s", sys.platform)
